n_params = gradient.size

# Flip layer order so index 0 corresponds to the TOP (y=+50) instead of bottom.
first = gradient[::-1]
x = np.arange(n_params)

# Presentation-friendly typography
plt.rcParams.update({
    "font.size": 16,
    "axes.titlesize": 20,
    "axes.labelsize": 18,
    "xtick.labelsize": 15,
    "ytick.labelsize": 15,
    "legend.fontsize": 15,
    "axes.linewidth": 1.2,
    "lines.linewidth": 2.2,
})

fig, ax = plt.subplots(figsize=(12, 5.5))

# SRV reference zones (after flipping layer order)
ax.axvspan(132, 139, color="orange", alpha=0.18, label="Low-perm SRV zone")
ax.axvspan(60, 71, color="green", alpha=0.18, label="High-perm SRV zone")

ax.axhline(0.0, color="firebrick", ls="--", lw=1.6, label="Zero (truth)", zorder=2)
ax.plot(x, first, color="#1f4e79", label="Gradient (iteration 1)", zorder=3)

ax.set_xlim(0, n_params - 1)
y_pad = 0.05 * (first.max() - first.min() + 1e-12)
ax.set_ylim(first.min() - y_pad, first.max() + y_pad)

ax.set_xlabel("Parameter Index (top → bottom)")
ax.set_ylabel("Gradient Value")
ax.set_title("Initial Gradient — Iteration 1")

ax.grid(True, ls=":", lw=0.8, alpha=0.6)
ax.legend(loc="lower right", framealpha=0.95, fontsize=11)

plt.tight_layout()

out_dir = "scripts/DSS_history_match/optimizer_input_file_test/perm5layer_100_v2strain/inv"
png_path = os.path.join(out_dir, "gradient_iteration1.png")
fig.savefig(png_path, dpi=300, bbox_inches="tight")
print(f"Saved to {png_path}")

plt.show()
